export default function SendMoneyFlow() {
  const [payees, setPayees] = useState([]);
  const [accounts, setAccounts] = useState([]);
  const [step, setStep] = useState("compose"); // compose | review | awaiting | done
  const [payeeId, setPayeeId] = useState("");
  const [amountDollars, setAmountDollars] = useState("");
  const [memo, setMemo] = useState("");
  const [error, setError] = useState("");
  const [result, setResult] = useState(null);

  useEffect(() => {
    tools.host_listPayees({}).then((r) => setPayees(r.data ?? r));
    tools.host_listAccounts({}).then((r) => setAccounts(r.data ?? r));
  }, []);

  const checking = accounts.find((a) =>
    (a.type ?? a.accountType ?? "").toLowerCase().includes("check") ||
    (a.name ?? "").toLowerCase().includes("check")
  ) ?? accounts[0];

  const selectedPayee = payees.find((p) => String(p.id) === String(payeeId));
  const amountCents = Math.round(parseFloat(amountDollars) * 100);
  const valid = selectedPayee && amountDollars && !isNaN(amountCents) && amountCents > 0;

  const handleSend = async () => {
    setStep("awaiting");
    try {
      const res = await tools.host_transferMoney({
        amount: amountCents,
        recipient_name: selectedPayee.name,
        memo: memo || undefined,
      });
      setResult(res);
      setStep("done");
    } catch (e) {
      setError(e?.message ?? "Something went wrong.");
      setStep("review");
    }
  };

  const reset = () => {
    setPayeeId(""); setAmountDollars(""); setMemo("");
    setError(""); setResult(null); setStep("compose");
  };

  const surface = {
    background: "var(--vendo-color-surface)",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-large)",
    padding: "28px 24px",
    fontFamily: "var(--vendo-font-family)",
    color: "var(--vendo-color-text)",
    maxWidth: 480,
    margin: "0 auto",
  };

  const label = {
    display: "block",
    fontSize: 12,
    fontWeight: 600,
    color: "var(--vendo-color-muted)",
    letterSpacing: "0.04em",
    textTransform: "uppercase",
    marginBottom: 6,
  };

  const inputStyle = {
    width: "100%",
    boxSizing: "border-box",
    padding: "10px 12px",
    fontSize: 15,
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-small)",
    background: "var(--vendo-color-background)",
    color: "var(--vendo-color-text)",
    fontFamily: "var(--vendo-font-family)",
    outline: "none",
  };

  const primaryBtn = {
    width: "100%",
    padding: "12px 0",
    fontSize: 15,
    fontWeight: 600,
    background: "var(--vendo-color-accent)",
    color: "var(--vendo-color-accent-text)",
    border: "none",
    borderRadius: "var(--vendo-radius-small)",
    cursor: "pointer",
    fontFamily: "var(--vendo-font-family)",
  };

  const ghostBtn = {
    ...primaryBtn,
    background: "transparent",
    color: "var(--vendo-color-text)",
    border: "1px solid var(--vendo-color-border)",
    marginTop: 8,
  };

  const divider = {
    borderTop: "1px solid var(--vendo-color-border)",
    margin: "20px 0",
  };

  const reviewRow = (lbl, val) => (
    <div key={lbl} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 0" }}>
      <span style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>{lbl}</span>
      <span style={{ fontWeight: 600, fontSize: 15 }}>{val}</span>
    </div>
  );

  if (step === "compose") {
    return (
      <div style={surface}>
        <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 24 }}>Send money</div>

        <div style={{ marginBottom: 18 }}>
          <label style={label}>To</label>
          <select
            value={payeeId}
            onChange={(e) => setPayeeId(e.target.value)}
            style={inputStyle}
          >
            <option value="">Choose a payee…</option>
            {payees.map((p) => (
              <option key={p.id} value={p.id}>{p.name}</option>
            ))}
          </select>
        </div>

        <div style={{ marginBottom: 18 }}>
          <label style={label}>Amount</label>
          <div style={{ position: "relative" }}>
            <span style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "var(--vendo-color-muted)", fontSize: 15 }}>$</span>
            <input
              type="number"
              min="0.01"
              step="0.01"
              placeholder="0.00"
              value={amountDollars}
              onChange={(e) => setAmountDollars(e.target.value)}
              style={{ ...inputStyle, paddingLeft: 26 }}
            />
          </div>
        </div>

        <div style={{ marginBottom: 24 }}>
          <label style={label}>Note <span style={{ fontWeight: 400, textTransform: "none", letterSpacing: 0 }}>(optional)</span></label>
          <input
            type="text"
            placeholder="What's this for?"
            value={memo}
            onChange={(e) => setMemo(e.target.value)}
            style={inputStyle}
          />
        </div>

        {checking && (
          <div style={{ background: "var(--vendo-color-background)", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-small)", padding: "10px 14px", marginBottom: 20, fontSize: 13, color: "var(--vendo-color-muted)" }}>
            Sending from <strong style={{ color: "var(--vendo-color-text)" }}>{checking.name}</strong>
            {checking.balanceCents != null && (
              <span> · Balance {fmt.money(checking.balanceCents)}</span>
            )}
          </div>
        )}

        <button
          style={{ ...primaryBtn, opacity: valid ? 1 : 0.45, cursor: valid ? "pointer" : "not-allowed" }}
          disabled={!valid}
          onClick={() => setStep("review")}
        >
          Review transfer
        </button>
      </div>
    );
  }

  if (step === "review") {
    return (
      <div style={surface}>
        <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 6 }}>Review transfer</div>
        <div style={{ color: "var(--vendo-color-muted)", fontSize: 14, marginBottom: 24 }}>Confirm the details before sending.</div>

        <div style={{ textAlign: "center", marginBottom: 20 }}>
          <div style={{ fontSize: 40, fontWeight: 800, letterSpacing: "-1px" }}>{fmt.money(amountCents)}</div>
          <div style={{ color: "var(--vendo-color-muted)", fontSize: 14, marginTop: 4 }}>to {selectedPayee?.name}</div>
        </div>

        <div style={divider} />

        {reviewRow("To", selectedPayee?.name)}
        {reviewRow("From", checking?.name ?? "Checking")}
        {memo && reviewRow("Note", memo)}
        {checking?.balanceCents != null && reviewRow("Available balance", fmt.money(checking.balanceCents))}

        <div style={divider} />

        {error && (
          <div style={{ color: "var(--vendo-color-danger)", fontSize: 13, marginBottom: 12 }}>{error}</div>
        )}

        <button style={primaryBtn} onClick={handleSend}>
          Send {fmt.money(amountCents)}
        </button>
        <button style={ghostBtn} onClick={() => { setError(""); setStep("compose"); }}>
          Back
        </button>
      </div>
    );
  }

  if (step === "awaiting") {
    return (
      <div style={{ ...surface, textAlign: "center" }}>
        <div style={{ fontSize: 32, marginBottom: 16 }}>⏳</div>
        <div style={{ fontSize: 18, fontWeight: 700, marginBottom: 8 }}>Awaiting your approval…</div>
        <div style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>
          Sending {fmt.money(amountCents)} to {selectedPayee?.name}. Please confirm in your approval queue.
        </div>
      </div>
    );
  }

  if (step === "done") {
    return (
      <div style={{ ...surface, textAlign: "center" }}>
        <div style={{ fontSize: 40, marginBottom: 16 }}>✓</div>
        <div style={{ fontSize: 22, fontWeight: 700, marginBottom: 8 }}>Transfer sent</div>
        <div style={{ fontSize: 32, fontWeight: 800, marginBottom: 4 }}>{fmt.money(amountCents)}</div>
        <div style={{ color: "var(--vendo-color-muted)", fontSize: 14, marginBottom: 28 }}>to {selectedPayee?.name}</div>
        <button style={primaryBtn} onClick={reset}>Send another</button>
      </div>
    );
  }

  return null;
}
